Actually, I realize I need to think about the linked charts interaction more carefully. Chart.js 4.x has `setActiveElements` and `tooltip.setActiveElements` methods. Let me use those.

```javascript
function syncCharts(sourceChart, targetChart, index) {
  if (index === null || index === undefined) {
    targetChart.setActiveElements([]);
    targetChart.tooltip.setActiveElements([], {x: 0, y: 0});
    targetChart.update('none');
    return;
  }
  const meta = targetChart.getDatasetMeta(0);
  if (meta.data[index]) {
    targetChart.setActiveElements([{datasetIndex: 0, index: index}]);
    targetChart.tooltip.setActiveElements([{datasetIndex: 0, index: index}], {x: meta.data[index].x, y: meta.data[index].y});
    targetChart.update('none');
  }
}
```

